  /// Extract comments. Default: false.
  final bool comments;

  /// Extract docstrings. Default: false.
  final bool docstrings;

  /// Extract symbol definitions. Default: false.
  final bool symbols;

  /// Include parse diagnostics. Default: false.
  final bool diagnostics;

