/// Complete analysis result from processing a source file.
///
/// Contains metrics, structural analysis, imports/exports, comments,
/// docstrings, symbols, diagnostics, and optionally chunked code segments.
/// Fields are populated based on the `ProcessConfig` flags.
///
/// # Fields
///
/// - `language` - The language used for parsing
/// - `metrics` - Always computed: line counts, byte sizes, error counts
/// - `structure` - Functions, classes, structs (when `config.structure = true`)
/// - `imports` - Import statements (when `config.imports = true`)
/// - `exports` - Export statements (when `config.exports = true`)
/// - `comments` - Comments (when `config.comments = true`)
/// - `docstrings` - Docstrings (when `config.docstrings = true`)
/// - `symbols` - Symbol definitions (when `config.symbols = true`)
/// - `diagnostics` - Parse errors (when `config.diagnostics = true`)
/// - `chunks` - Chunked code segments (when `config.chunk_max_size` is set)
class ProcessResult {
  final String language;
  final FileMetrics metrics;
  final List<StructureItem> structure;
  final List<ImportInfo> imports;
  final List<ExportInfo> exports;
  final List<CommentInfo> comments;
  final List<DocstringInfo> docstrings;
  final List<SymbolInfo> symbols;
  final List<Diagnostic> diagnostics;
  final List<CodeChunk> chunks;

  const ProcessResult({
    required this.language,
    required this.metrics,
    required this.structure,
    required this.imports,
    required this.exports,
    required this.comments,
    required this.docstrings,
    required this.symbols,
    required this.diagnostics,
    required this.chunks,
  });

  @override
  int get hashCode =>
      language.hashCode ^
      metrics.hashCode ^
      structure.hashCode ^
      imports.hashCode ^
      exports.hashCode ^
      comments.hashCode ^
      docstrings.hashCode ^
      symbols.hashCode ^
      diagnostics.hashCode ^
      chunks.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is ProcessResult &&
          runtimeType == other.runtimeType &&
          language == other.language &&
          metrics == other.metrics &&
          structure == other.structure &&
          imports == other.imports &&
          exports == other.exports &&
          comments == other.comments &&
          docstrings == other.docstrings &&
          symbols == other.symbols &&
          diagnostics == other.diagnostics &&
          chunks == other.chunks;
}

/// Byte and line/column range in source code.
///
/// Represents both byte offsets (for slicing) and human-readable line/column
/// positions (for display and diagnostics).
class Span {
  final PlatformInt64 startByte;
  final PlatformInt64 endByte;
  final PlatformInt64 startLine;
  final PlatformInt64 startColumn;
  final PlatformInt64 endLine;
  final PlatformInt64 endColumn;

