  @override
  int get hashCode =>
      startByte.hashCode ^
      endByte.hashCode ^
      startLine.hashCode ^
      startColumn.hashCode ^
      endLine.hashCode ^
      endColumn.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
